fn check_wasmtime() -> Result<()> {
    if Command::new("wasmtime")
        .arg("--version")
        .output()
        .is_err()
    {
        anyhow::bail!(
            "wasmtime is not installed or not in PATH\n\
             Install wasmtime from: https://wasmtime.dev/"
        );
    }
    Ok(())
}

fn validate_args(function: &str, component: &str) -> Result<()> {
    if function.is_empty() {
        anyhow::bail!("Function name cannot be empty");
    }

    if !Path::new(component).exists() {
        anyhow::bail!("Component file not found: {}", component);
    }

    if !component.ends_with(".wasm") {
        eprintln!("⚠️  Warning: File does not have .wasm extension: {}", component);
    }

    Ok(())
}

