fn run_component(cli: &Cli) -> Result<()> {
    println!("ℹ️  Running component: {}", cli.component);
    println!("ℹ️  Function: {}", cli.function);
    
    if !cli.args.is_empty() {
        println!("ℹ️  Arguments: {}", cli.args.join(" "));
    }

    // Build wasmtime command
    let mut cmd = Command::new("wasmtime");
    cmd.args(["run", "--invoke", &cli.function, &cli.component]);
    cmd.args(&cli.args);

    // Add additional wasmtime arguments if specified
    if let Some(ref wasmtime_args) = cli.wasmtime_args {
        println!("ℹ️  Additional wasmtime args: {}", wasmtime_args);
        for arg in wasmtime_args.split_whitespace() {
            cmd.arg(arg);
        }
    }

    if cli.verbose {
        println!("ℹ️  Command: {:?}", cmd);
    }

    // Run the component
    let output = cmd.output().context("Failed to execute wasmtime")?;

    if output.status.success() {
        println!("✅ Component executed successfully");
        if !output.stdout.is_empty() {
            print!("{}", String::from_utf8_lossy(&output.stdout));
        }
    } else {
        println!("❌ Component execution failed (exit code: {})", output.status);
        if !output.stderr.is_empty() {
            eprint!("{}", String::from_utf8_lossy(&output.stderr));
        }
        if !output.stdout.is_empty() {
            print!("{}", String::from_utf8_lossy(&output.stdout));
        }
        if cli.strict {
            std::process::exit(output.status.code().unwrap_or(1));
        }
    }

    Ok(())
}

